import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Routes, Route, useNavigate, useParams, useLocation } from 'react-router-dom';
import { createResourceService } from '../../services/api.service';
import { useNotifier } from '../../context/NotificationContext';
import { Serializer } from '../../utils/serializer';
import { setPageTitle } from '../../hooks/usePageTitle';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import moment from 'moment';
import DataTable from '../../components/common/DataTable';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import useForm from '../../hooks/useForm';
import { FormInput, FormTextarea } from '../../components/common/FormFields';

const parentService = createResourceService('employees');

const ChildPage = ({ onSuccess }) => {
    const navigate = useNavigate();
    const { notify } = useNotifier();
    const { id: encodedId } = useParams();
    const location = useLocation();
    const queryClient = useQueryClient();

    const tableState = useMemo(() => location.state?.tableState || {}, [location.state]);
    const decodedId = useMemo(() => {
        if (encodedId === 'new') return 'new';
        try { return Serializer.decode(encodedId); } catch { return null; }
    }, [encodedId]);
    const isEditMode = encodedId !== 'new';

    const [item, setItem] = useState(null);
    const [loading, setLoading] = useState(isEditMode);
    const [error, setError] = useState(null);
    const [allEmployeeIds, setAllEmployeeIds] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);

    const [photoPreview, setPhotoPreview] = useState(null);
    const [photoFile, setPhotoFile] = useState(null);

    const schema = useMemo(() => ({
        fn: { required: true, label: 'First Name' },
        sn: { required: true, label: 'Last Name' },
        email: { required: true, type: 'email', label: 'Email Address' }
    }), []);

    const initialValues = useMemo(() => ({
        fn: '',
        mn: '',
        sn: '',
        phone: '',
        email: '',
        address: '',
    }), []);

    const { values, errors, handleChange, handleSubmit, resetForm, setValues } = useForm(initialValues, schema);

    useEffect(() => {
        if (!decodedId && isEditMode) navigate('/admin/table-parent');
    }, [decodedId, isEditMode, navigate]);

    useEffect(() => {
        if (!isEditMode) setPageTitle('New Employee');
        else setPageTitle(loading ? 'Loading...' : (item ? `${item.fn} ${item.sn}` : 'Edit Employee'));
    }, [isEditMode, item, loading]);

    const fetchEmployeeData = useCallback(async () => {
        if (!isEditMode || !decodedId) return;
        setLoading(true);
        try {
            const response = await parentService.getAll({ id: decodedId, _t: Date.now() });
            const data = response.data.data[0];
            if (data) {
                setItem(data);
                setValues({
                    fn: data.fn || '',
                    mn: data.mn || '',
                    sn: data.sn || '',
                    phone: data.phone || '',
                    email: data.email || '',
                    address: data.address || '',
                });

                if (data.photoUrl) {
                    setPhotoPreview(`${data.photoUrl}?t=${Date.now()}`);
                } else { setPhotoPreview('/defaults/avatar.png'); }
            } else { navigate('/admin/table-parent'); }
        } catch { setError('Failed to fetch'); } finally { setLoading(false); }
    }, [decodedId, isEditMode, navigate, setValues]);

    useEffect(() => {
        const fetchIds = async () => {
            try {
                const pars = { ...tableState };
                if (pars.filters) { Object.assign(pars, pars.filters); delete pars.filters; }
                const resp = await parentService.getAll({ ...pars, page: 1, limit: 100000, searchableColumns: 'fn,sn,email,phone' });
                setAllEmployeeIds(resp.data.data.map(e => e.id));
            } catch (e) { console.error(e); }
        };
        fetchIds();
    }, [tableState]);

    useEffect(() => {
        if (decodedId && decodedId !== 'new' && allEmployeeIds.length > 0) {
            setCurrentIndex(allEmployeeIds.findIndex(id => String(id) === String(decodedId)));
        }
    }, [decodedId, allEmployeeIds]);

    useEffect(() => {
        if (isEditMode) fetchEmployeeData();
        else {
            resetForm();
            setPhotoPreview('/defaults/avatar.png');
        }
    }, [decodedId, isEditMode, fetchEmployeeData, resetForm]);

    const handlePhotoChange = (e) => { const f = e.target.files[0]; if (f) { setPhotoFile(f); setPhotoPreview(URL.createObjectURL(f)); } };
    const handleBack = () => navigate('/admin/table-parent');
    const handleRetry = (e) => { e.preventDefault(); fetchEmployeeData(); };

    const mutation = useMutation({
        mutationFn: async ({ formData, itemId }) => {
            if (itemId) {
                return await parentService.update(itemId, formData);
            } else {
                return await parentService.create(formData);
            }
        },
        onSuccess: (response, { itemId }) => {
            const updatedRecord = response.data.data || response.data;
            const newPhotoTs = photoFile ? Date.now() : null;

            if (itemId) {
                notify({ message: 'Updated successfully.', style: 'success' });
            } else {
                notify({ message: 'Created successfully.', style: 'success' });
            }

            // Invalidate the 'Employee' query to refetch the list
            queryClient.invalidateQueries({ queryKey: ['Employee'] });

            if (onSuccess) {
                onSuccess(itemId, updatedRecord, newPhotoTs);
            }

            navigate('/admin/table-parent', { state: { tableState } });
        },
        onError: (err) => {
            notify({ message: `Failed: ${err.message}`, style: 'error' });
        }
    });

    const onFormSubmit = (formValues) => {
        const fd = new FormData();
        Object.keys(formValues).forEach(key => fd.append(key, formValues[key]));
        if (photoFile) fd.append('photo', photoFile);

        mutation.mutate({ formData: fd, itemId: isEditMode ? decodedId : null });
    };

    const onFormReset = (e) => {
        if (e) e.preventDefault();
        if (isEditMode && item) {
            setValues({
                fn: item.fn || '',
                mn: item.mn || '',
                sn: item.sn || '',
                phone: item.phone || '',
                email: item.email || '',
                address: item.address || '',
            });
            setPhotoFile(null);
            if (item.photoUrl) setPhotoPreview(`${item.photoUrl}?t=${Date.now()}`);
            else setPhotoPreview('/defaults/avatar.png');
        } else {
            resetForm();
            setPhotoFile(null); setPhotoPreview('/defaults/avatar.png');
        }
    };

    const handleNav = (offset) => {
        const nextId = allEmployeeIds[currentIndex + offset];
        if (nextId) navigate(`/admin/table-parent/${Serializer.encode(nextId)}`, { state: { tableState } });
    };

    const loading_skeleton = (
        <div className='is-loading-wrap template-table-tab'>
            <div className='is-loading-row'>
                <div className='is-loading-row'>
                    <i className='is-loading profile'></i>
                    <span>
                        <div className='is-loading-row'>
                            <div className='is-loading-wrap w5-fx'>
                                <i className='is-loading wrap'></i><u className='is-loading wrap'></u>
                            </div>
                            <div className='is-loading-wrap w5-fx'>
                                <i className='is-loading wrap'></i><u className='is-loading wrap'></u>
                            </div>
                        </div>
                        <div className='is-loading-wrap'>
                            <i className='is-loading wrap'></i><u className='is-loading wrap'></u>
                        </div>
                    </span>
                </div>
            </div>
        </div>
    );

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'>
                    <button className='admin-pager-back' onClick={handleBack}><Icon icon={icons.arrowLeft} /></button>
                    <span>
                        <h2>{isEditMode ? 'Edit Record' : 'Add Record'}</h2>
                        <p>{isEditMode ? item ? `${item.fn} ${item.sn}` : 'Loading...' : 'Create New Record'}</p>
                    </span>
                </div>
                {isEditMode && allEmployeeIds.length > 1 && (
                    <div className='admin-pager-navs'>
                        <button className='button btn-outlined icon' onClick={() => handleNav(-1)} disabled={currentIndex <= 0}><Icon icon={icons.chevronLeft} /></button>
                        <button className='button btn-outlined icon' onClick={() => handleNav(1)} disabled={currentIndex >= allEmployeeIds.length - 1}><Icon icon={icons.chevronRight} /> </button>
                    </div>
                )}
            </header>
            <div className='admin-pager-body'>
                {error ?
                    (<div className='table-error-case'> <div className='pagelet'><div className='table-error'><Icon icon={icons.alertCircle} /> <p>Failed loading data.</p><a className='link' onClick={handleRetry}>Try Again</a></div></div> </div>) :
                    (<div className='w5'>
                        <form id='employee_form' noValidate className='pagelet' onSubmit={handleSubmit(onFormSubmit)} onReset={onFormReset} autoComplete='on' >
                            <div className='pagelet-in' >
                                <div className='form-case'>
                                    {loading ? loading_skeleton : (
                                        <>
                                            <div className='form-row form-profile'>
                                                <div className='form-profile-photo'>
                                                    <img src={photoPreview || '/defaults/avatar.png'} alt='Profile' onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }} /><label htmlFor='photo-upload'>Select Photo</label>
                                                    <input id='photo-upload' type='file' accept='image/*' onChange={handlePhotoChange} />
                                                </div>
                                                <div className='form-profile-info'>
                                                    <div className='form-row'>
                                                        <FormInput label="First Name" name="fn" placeholder="First Name" value={values.fn} error={errors.fn} onChange={handleChange} required className="w5-fx" />
                                                        <FormInput label="Middle Name" name="mn" placeholder="Middle Name" value={values.mn} onChange={handleChange} className="w5-fx" />
                                                    </div>
                                                    <FormInput label="Last Name" name="sn" placeholder="Last Name" value={values.sn} error={errors.sn} onChange={handleChange} required />
                                                </div>
                                            </div>
                                            <div className='form-dvr'></div>
                                            <div className='form-row'>
                                                <FormInput label="Phone" name="phone" placeholder="Phone Number" value={values.phone} onChange={handleChange} className="w5" autoComplete='off' />
                                                <FormInput label="Email Address" name="email" type="email" placeholder="Email" value={values.email} error={errors.email} onChange={handleChange} required className="w5" autoComplete='off' />
                                            </div>
                                            <FormTextarea label="Address" name="address" placeholder="Address" rows={2} value={values.address} onChange={handleChange} autoComplete='off' />
                                        </>
                                    )}
                                </div>
                            </div>

                            <div className='pagelet-foot'>
                                <button type='reset' className='button btn-secondary' disabled={loading}><Icon icon={icons.times} />Reset</button>
                                <button type='submit' className='button' disabled={loading}><Icon icon={icons.send} />Submit</button>
                            </div>
                        </form>
                    </div>)}
            </div>
        </div>
    );
};


const EmployeeList = ({ tableRef, initialLoadTime, photoOverrides }) => {
    const navigate = useNavigate();
    const [tableState, setTableState] = useState({});

    const tableColumns = useMemo(() => [{
        key: 'fn', label: 'Full Name', type: 0, class: 'mob-flex', sortable: true,
        render: (item, photoUrl) => {
            let displayUrl = photoUrl || '/defaults/avatar.png';
            if (displayUrl.includes('?')) displayUrl = displayUrl.split('?')[0];

            const timestampToUse = photoOverrides[item.id] || initialLoadTime;
            displayUrl = `${displayUrl}?t=${timestampToUse}`;

            return (
                <div className='td-user'>
                    <div className='td-user-photo'>
                        <img
                            key={displayUrl}
                            src={displayUrl}
                            alt={`${item.fn} ${item.sn}`}
                            loading='lazy'
                            onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }}
                        />
                    </div>
                    <div className='tr-name'>
                        <b className='link' onClick={() => { navigate(`/admin/table-parent/${Serializer.encode(item.id)}`, { state: { tableState } }) }}>
                            {`${item.fn} ${item.mn ? item.mn : ''} ${item.sn}`}
                        </b>
                        <p>{item.email}</p>
                    </div>
                </div>
            );
        }
    },
    { key: 'phone', label: 'Phone', type: 1, class: 'mob-full', sortable: true },
    { key: 'bday', label: 'Birthday', type: 1, class: 'mob-full', sortable: true, render: (item) => item.bday ? moment(item.bday).format('MMM DD, YYYY') : '' },
    { key: 'address', label: 'Address', type: 1, class: 'mob-full', sortable: true },
    ], [navigate, tableState, photoOverrides, initialLoadTime]);

    const headerActions = useMemo(() => [{ text: 'Add New', icon: icons.add, onClick: () => navigate('/admin/table-parent/new'), className: '' }], [navigate]);

    return (
        <DataTable
            key='employee-datatable'
            ref={tableRef}
            resourceName='Employee'
            apiService={parentService}
            columns={tableColumns}
            config={{ add: false, edit: false, searchables: ['fn', 'sn', 'email', 'phone'], headerActions: headerActions, onStateChange: setTableState }}
        />
    );
};

const CombinedView = () => {
    const { id } = useParams();
    const showChildPage = id !== undefined;
    const tableRef = useRef(null);

    const initialLoadTime = useMemo(() => Date.now(), []);
    const [photoOverrides, setPhotoOverrides] = useState({});

    const handleListUpdate = useCallback((itemId, updatedData, newPhotoTs) => {
        if (itemId && newPhotoTs) { setPhotoOverrides(prev => ({ ...prev, [itemId]: newPhotoTs })); }
        if (tableRef.current) {
            // Since DataTable now uses React Query, we can just trigger a refetch
            tableRef.current.refreshData();
        }
    }, []);

    return (
        <div>
            <div style={{ display: showChildPage ? 'none' : 'block' }}>
                <EmployeeList
                    tableRef={tableRef}
                    initialLoadTime={initialLoadTime}
                    photoOverrides={photoOverrides}
                />
            </div>
            {showChildPage && <ChildPage onSuccess={handleListUpdate} />}
        </div>
    );
};

const TableParent = () => {
    return (
        <Routes>
            <Route path="/" element={<CombinedView />} />
            <Route path="/:id" element={<CombinedView />} />
        </Routes>
    );
};

export default TableParent;